import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

// File patterns to ignore
const IGNORED_PATTERNS = [
  /^\.git\//,           // Git directory
  /^\.git$/,            // Git directory (root)
  /\.o$/,              // Object files
  /\.a$/,              // Static libraries
  /\.so$/,             // Shared libraries
  /\.dylib$/,          // macOS dynamic libraries
  /\.dll$/,            // Windows DLLs
  /\.exe$/,            // Windows executables
  /\.bin$/,            // Binary files
  /\.dat$/,            // Data files
  /^a\.out$/,          // Default compiler output
  /\.pyc$/,            // Python compiled files
  /^__pycache__$/,     // Python cache directory
  /\.class$/,          // Java compiled files
  /node_modules/,      // Node.js modules
  /\.DS_Store$/,       // macOS system files
  /\.env$/,            // Environment files
  /\.log$/             // Log files
];

// Check if a file should be ignored
const shouldIgnoreFile = (filename) => {
  return IGNORED_PATTERNS.some(pattern => pattern.test(filename));
};

// Create axios instance with timeout and retry config
const apiClient = axios.create({
  baseURL: API_BASE_URL,
  timeout: 30000, // 30 seconds
  headers: {
    'Content-Type': 'application/json',
  }
});

// Add retry logic
apiClient.interceptors.response.use(null, async (error) => {
  const { config } = error;
  if (!config || !config.retry) {
    return Promise.reject(error);
  }
  config.retry -= 1;
  const delayRetry = new Promise(resolve => setTimeout(resolve, config.retryDelay || 1000));
  await delayRetry;
  return apiClient(config);
});

export const uploadFile = async (file, relativePath = '') => {
  // Skip ignored files
  if (shouldIgnoreFile(file.name) || (relativePath && shouldIgnoreFile(relativePath))) {
    console.log(`Skipping ignored file: ${relativePath}/${file.name}`);
    return {
      status: 'skipped',
      message: 'File type is not allowed'
    };
  }

  // Check file size (max 50MB)
  const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
  if (file.size > MAX_FILE_SIZE) {
    console.log(`File too large: ${file.name} (${file.size} bytes)`);
    return {
      status: 'skipped',
      message: 'File size exceeds 50MB limit'
    };
  }

  const formData = new FormData();
  const fullPath = relativePath ? `${relativePath}/${file.name}` : file.name;
  formData.append('file', file);
  formData.append('path', fullPath);

  try {
    const response = await apiClient.post('/upload', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
      retry: 3,
      retryDelay: 1000,
      timeout: 60000, // 60 seconds for uploads
      onUploadProgress: (progressEvent) => {
        const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
        console.log(`Upload progress for ${file.name}: ${percentCompleted}%`);
      }
    });
    return response.data;
  } catch (error) {
    console.error('Upload error:', {
      file: file.name,
      path: fullPath,
      error: error.message,
      response: error.response?.data
    });
    throw new Error(`Failed to upload ${file.name}: ${error.message}`);
  }
};

export const uploadFiles = async (files, path = '') => {
  console.log(`Starting upload of ${files.length} files to path: ${path}`);
  const results = {
    successful: [],
    failed: [],
    skipped: []
  };

  // Group files by folder and filter out ignored files
  const filesByFolder = files.reduce((acc, file) => {
    const relativePath = file.webkitRelativePath || file.path || '';
    const folder = relativePath.split('/').slice(0, -1).join('/');

    // Skip ignored files
    if (shouldIgnoreFile(file.name) || (folder && shouldIgnoreFile(folder))) {
      results.skipped.push({
        file: relativePath || file.name,
        reason: 'File type not allowed'
      });
      return acc;
    }

    // Skip large files
    if (file.size > 50 * 1024 * 1024) {
      results.skipped.push({
        file: relativePath || file.name,
        reason: 'File size exceeds 50MB limit'
      });
      return acc;
    }

    if (!acc[folder]) acc[folder] = [];
    acc[folder].push(file);
    return acc;
  }, {});

  // Upload files by folder
  for (const [folder, folderFiles] of Object.entries(filesByFolder)) {
    for (const file of folderFiles) {
      try {
        console.log(`Processing file: ${file.name} in folder: ${folder}`);
        const result = await uploadFile(file, folder);
        if (result.status === 'skipped') {
          results.skipped.push({
            file: folder ? `${folder}/${file.name}` : file.name,
            reason: result.message
          });
        } else {
          results.successful.push({
            file: folder ? `${folder}/${file.name}` : file.name,
            result
          });
        }
      } catch (error) {
        console.error(`Failed to upload ${file.name}:`, error);
        results.failed.push({
          file: folder ? `${folder}/${file.name}` : file.name,
          error: error.message || 'Unknown error occurred'
        });
      }
    }
  }

  console.log('Upload results:', results);
  return results;
};

export const deleteFile = async (path) => {
  try {
    const response = await apiClient.delete('/delete', {
      data: { path }
    });
    return response.data;
  } catch (error) {
    console.error('Delete error:', error);
    throw error;
  }
};

export const deleteFolder = async (folderPath) => {
  try {
    const response = await apiClient.delete('/delete-folder', {
      data: { path: folderPath }
    });
    return response.data;
  } catch (error) {
    console.error('Delete folder error:', error);
    throw error;
  }
};

export const listFiles = async () => {
  try {
    const response = await apiClient.get('/files');
    return response.data;
  } catch (error) {
    console.error('List files error:', error);
    return [];
  }
};

export const readFile = async (path) => {
  try {
    const response = await apiClient.get('/read', { params: { path } });
    return response.data.content;
  } catch (error) {
    throw error;
  }
};

export const searchFiles = async (query) => {
  try {
    const response = await apiClient.get('/search', { params: { query } });
    return response.data.results || [];
  } catch (error) {
    return [];
  }
};

export default apiClient;
